declare li_chk integer;
BEGIN

  -- Auto Create
  if coalesce(trim(both NEW.collateral_no)::text, '') = '' then
    if pka.auto_seqno then
        select max((collateral_no)::numeric ) into STRICT NEW.collateral_no
        from sc_lon_m_contract_coll 
        where (loan_contract_no = NEW.loan_contract_no)
        and is_number(collateral_no) = '1';
      NEW.collateral_no := coalesce(NEW.collateral_no,0) + 1;
    end if;
  end if;
  --//-- Insert 
  if coalesce(OLD.loan_contract_no::text, '') = '' and (NEW.loan_contract_no IS NOT NULL AND NEW.loan_contract_no::text <> '') then
    if pka.auto_entry then 
        NEW.entry_id := current_setting('app.login_id', true);
        NEW.entry_date := statement_timestamp();
        NEW.entry_branch := current_setting('app.login_br', true);
    end if;
  end if;

  if coalesce(NEW.status::text, '') = '' then NEW.status := '0';end if;
  if coalesce(NEW.evaluate_amount::text, '') = '' then NEW.evaluate_amount :=0;end if;
  if coalesce(NEW.used_amount::text, '') = '' then NEW.used_amount :=0;end if;
  if coalesce(NEW.full_amount::text, '') = '' then NEW.full_amount :=0;end if;
  if coalesce(NEW.mustcoll_loan::text, '') = '' or NEW.mustcoll_loan = ' ' then NEW.mustcoll_loan := '0';end if;

  if coalesce(NEW.evaluate_amount::text, '') = '' then NEW.evaluate_amount := NEW.used_amount;end if;
  if coalesce(NEW.collateral_amount::text, '') = '' then NEW.collateral_amount := NEW.used_amount;end if;

--  --//-- Insert sc_mem_m_member_special
