  if coalesce(NEW.status::text, '') = '' or NEW.status = ' ' then NEW.status := '0';end if;

--  --Niorn krabi 2021-01-19  เก็บกับคนค้ำ
  if coalesce(NEW.keep_coll_status::text, '') = '' or NEW.keep_coll_status = ' ' then NEW.keep_coll_status := '0';end if;
  if coalesce(NEW.keep_coll_amount::text, '') = ''  then NEW.keep_coll_amount := 0;end if;

RETURN NEW;
end
